<?php
require_once __DIR__ . '/billing.php';
require_once __DIR__ . '/payment_gateway.php';
require_once __DIR__ . '/revenue_access_governance.php';
function sf_billing_start_checkout_secure(int $planId): ?string{$pdo=sf_auth_db_required();$user=sf_auth_user();if(!$pdo||!$user){sf_auth_flash('warning','Sign in before starting checkout.');return null;}if(!sf_billing_is_ready()){sf_auth_flash('warning','Billing tables are not installed yet.');return null;}$plan=sf_billing_plan($planId);if(!$plan){sf_auth_flash('error','Membership plan was not found.');return null;}$token=bin2hex(random_bytes(24));$expires=(new DateTimeImmutable('+45 minutes'))->format('Y-m-d H:i:s');$provider=sf_payment_provider();$gateway=sf_payment_create_checkout(['checkout_token'=>$token,'amount_cents'=>(int)$plan['price_cents'],'currency'=>'USD','plan_name'=>(string)$plan['name'],'billing_interval'=>(string)$plan['billing_interval'],'customer_email'=>(string)$user['email'],'local_checkout_url'=>sf_url('billing-checkout.php?token='.urlencode($token))]);if(empty($gateway['ok'])){sf_auth_flash('error','Checkout could not be started: '.(string)($gateway['error']??'Payment provider unavailable.'));return null;}$url=(string)($gateway['checkout_url']??'');if($provider==='stripe'&&!preg_match('~^https://checkout\.stripe\.com/~',$url)){sf_auth_flash('error','Stripe did not return a valid hosted checkout URL.');return null;}$meta=['plan_slug'=>$plan['slug']??'','source'=>'subscribe_page','hosted_checkout_url'=>$url,'gateway_mode'=>$gateway['mode']??sf_payment_mode()];try{$stmt=$pdo->prepare("INSERT INTO subscription_checkouts (checkout_token,user_id,plan_id,provider,provider_checkout_id,status,amount_cents,currency,success_url,cancel_url,metadata_json,expires_at) VALUES (?,?,?,?,?,'pending',?,'USD',?,?,?,?)");$stmt->execute([$token,(int)$user['id'],(int)$plan['id'],(string)($gateway['provider']??$provider),(string)($gateway['provider_checkout_id']??''),(int)$plan['price_cents'],sf_url('billing-success.php?token='.urlencode($token)),sf_url('billing-cancel.php?token='.urlencode($token)),json_encode($meta,JSON_UNESCAPED_SLASHES),$expires]);return$token;}catch(Throwable$e){error_log('Stonefellow secure checkout start failed: '.$e->getMessage());sf_auth_flash('error','Checkout could not be started.');return null;}}
function sf_billing_checkout_hosted_url(array $checkout): string{$meta=[];if(!empty($checkout['metadata_json'])){$d=json_decode((string)$checkout['metadata_json'],true);if(is_array($d))$meta=$d;}$url=(string)($meta['hosted_checkout_url']??'');return preg_match('~^https://checkout\.stripe\.com/~',$url)?$url:'';}
?>